// 处理所有文档数据，合并文件夹信息
const allResults = $input.all();
let allDocuments = [];

// 文件夹映射
const folderMap = {
  '1xDNGIOGnsCsXs0KZCHwKOav96dQGith4': { name: '心理专题', category: 'psychology' },
  '1uKz9AOYftgvExoLPbiMvlEtdjY63YSB6': { name: '职场专题', category: 'workplace' },
  '125UBg7dLONmNg0ou9T4d8uVW_fsrJFH8': { name: '历史专题', category: 'history' },
  '1frvBLCJkyDaBffF_JXR4Px8DoIcL-75_': { name: '技术专题', category: 'tech' },
  '1hVM2Q2doBl2Sb9HeUvTawjxIhP_MGd6P': { name: '业务专题', category: 'business'}
};

// 遍历每个文件夹的结果
allResults.forEach(result => {
  if (result.json.files && result.json.files.length > 0) {
    result.json.files.forEach(file => {
      const folderId = file.parents[0];
      const folderInfo = folderMap[folderId];

      if (folderInfo) {
        allDocuments.push({
          json: {
            ...file,
            folderName: folderInfo.name,
            folderId: folderId,
            category: folderInfo.category
          }
        });
      }
    });
  }
});

console.log(`总共找到 ${allDocuments.length} 个文档`);
return allDocuments;

// 解析AI Agent的响应
const response = $input.first();
const aiResponse = response.json.output;
const originalDoc = $('Loop Over Items').first().json;

let frontMatter = aiResponse;

// 直接使用文档ID的后8位作为文件名
const docId = originalDoc.id;
const shortId = docId.slice(-8);
const fileName = $('判断文件状态').first().json.category + `-${shortId}.md`;

// 构建完整的Front Matter
const now = new Date();
const completeFrontMatter = {
  ...frontMatter,
  date: now.toISOString(),
  lastmod: now.toISOString(),
  categories: [originalDoc.folderName]
};

return {
  json: {
    originalDoc,
    frontMatter: completeFrontMatter,
    fileName,
    category: originalDoc.category
  }
};

