// 合并内容 + 图片处理 + Mermaid 处理
console.log("--- [合并内容] 节点开始执行 ---");
try {
    // 1. 获取由Merge节点合并后的单个输入项
    const input = $input.first();
    const data = input.json;
    console.log("收到的输入数据类型:", typeof data);
    console.log("收到的binary数据:", input.binary ? "存在" : "不存在");

    // 2. 严格检查合并后的数据是否有效
    if (!data || !data.frontMatter || !data.fileName) {
        console.error("错误：合并后的数据无效或不完整，将跳过此项。");
        return []; 
    }
    console.log(`数据检查通过: ${data.fileName}`);

    // 3. 准备Front Matter
    const fm = data.frontMatter;
    const frontMatterYaml = `title: "${fm.title || ''}"
description: "${fm.description || ''}"
tags: [${fm.tags ? fm.tags.map(tag => `"${tag}"`).join(', ') : ''}]
date: "${fm.date || ''}"
lastmod: "${fm.lastmod || ''}"
categories: [${fm.categories ? fm.categories.map(cat => `"${cat}"`).join(', ') : ''}]`;

    // 4. 获取Markdown内容
    let content = '';

    if (input.binary && input.binary.data) {
        if (Buffer.isBuffer(input.binary.data)) {
            content = input.binary.data.toString('utf8');
        } else {
            content = Buffer.from(input.binary.data).toString('utf8');
        }
        console.log("从binary数据获取内容，长度:", content.length);
    } else if (typeof data.data === 'string') {
        content = data.data;
        console.log("从data.data获取内容，长度:", content.length);
    } else if (typeof data.body === 'string') {
        content = data.body;
        console.log("从data.body获取内容，长度:", content.length);
    } else {
        console.error(`错误：无法找到文档内容，文档标题: ${data.frontMatter.title}`);
        return [];
    }

    // 5. 验证内容不为空
    if (!content || content.trim().length === 0) {
        console.error(`错误：文档内容为空，跳过处理: ${data.frontMatter.title}`);
        return [];
    }

    // 6. ===== Mermaid 处理：优先于图片处理，防止文本标记内URL被误识别 =====
    const mermaidList = [];
    let mermaidCounter = 0;
    const mermaidMatches = [];
    const mermaidRegex = /MERMAIDSTART[ \t]*\n([\s\S]*?)MERMAIDEND/gi;
    let mermaidMatch;
    while ((mermaidMatch = mermaidRegex.exec(content)) !== null) {
        mermaidCounter++;
        const fullBlock = mermaidMatch[0];
        const diagramCode = mermaidMatch[1].trim().split('\n').map(line => line.trimEnd()).join('\n').replace(/\\(.)/g, '$1');
        // 对 mermaid 代码做 base64 编码，供 mermaid.ink API 使用
        const base64Code = Buffer.from(JSON.stringify({ code: diagramCode, mermaid: { theme: 'default' } })).toString('base64url');
        const localFileName = `mermaid-${mermaidCounter}.svg`;
        mermaidMatches.push({ fullBlock, base64Code, localFileName });
        mermaidList.push({ base64Code, localFileName });
    }
    // 把 mermaid 标记块替换为本地 SVG 图片引用
    let processedContent = content;
    mermaidMatches.forEach(m => {
        processedContent = processedContent.replace(m.fullBlock, `![Mermaid 图表](./${m.localFileName})`);
    });
    console.log(`Mermaid 处理：找到 ${mermaidList.length} 个标记块，已替换为本地 SVG 路径`);
    // ===== Mermaid 处理结束 =====

    // 7. ===== 图片处理：提取并替换外部图片URL =====
    const imageList = [];
    let imageCounter = 0;
    const imageRegex = /!\[([^\]]*)\]\((https?:\/\/[^)]+)\)/g;
    let match;
    while ((match = imageRegex.exec(processedContent)) !== null) {
        const originalUrl = match[2];
        const isGoogleImage = /googleusercontent\.com|ggpht\.com|googleapis\.com\/drive/.test(originalUrl);
        if (isGoogleImage) {
            imageCounter++;
            const localFileName = `image-${imageCounter}.jpg`;
            imageList.push({ url: originalUrl, localFileName });
        }
    }
    imageList.forEach(img => {
        const escapedUrl = img.url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        processedContent = processedContent.replace(new RegExp(escapedUrl, 'g'), `./${img.localFileName}`);
    });
    console.log(`图片处理：找到 ${imageList.length} 张外部图片，已替换为本地相对路径`);
    // ===== 图片处理结束 =====
    // 8.5 ===== Base64 内联图片处理（Google Drawing / 嵌入式图片）=====
    const inlineImageList = [];
    let inlineCounter = 0;
    const inlineRefMap = {};

    // 匹配 [imageN]: <data:image/TYPE;base64,DATA> 定义行
    const base64DefRegex = /\[image(\d+)\]:\s*<data:image\/(\w+);base64,([^>]+)>/g;
    let defMatch;
    while ((defMatch = base64DefRegex.exec(processedContent)) !== null) {
        const refId = defMatch[1];
        const mimeType = defMatch[2];
        const base64Data = defMatch[3].replace(/\n/g, '');
        const ext = mimeType === 'jpeg' ? 'jpg' : mimeType;
        inlineCounter++;
        const localFileName = 'drawing-' + inlineCounter + '.' + ext;
        inlineRefMap[refId] = { localFileName };
        inlineImageList.push({ base64Data, localFileName });
    }

    // 替换 ![][imageN] 或 ![alt][imageN] 为本地路径
    processedContent = processedContent.replace(/!\[[^\]]*\]\[image(\d+)\]/g, (match, refId) => {
        const img = inlineRefMap[refId];
        return img ? '![](./' + img.localFileName + ')' : match;
    });

    // 删除 base64 定义行
    processedContent = processedContent.replace(/\n?\[image\d+\]:\s*<data:image\/\w+;base64,[^>]+>/g, '');

    console.log('Base64图片处理：找到 ' + inlineImageList.length + ' 张内联图片（Google Drawing）');
    // ===== Base64 内联图片处理结束 =====


    // 8. 合并完整文档
    const completeDocument = `---\n${frontMatterYaml}\n---\n${processedContent}`;
    const fileName = data.fileName;
    const slug = fileName.replace(/\.md$/, '');
    const category = data.category;

    const finalOutput = {
        json: {
            fileName,
            slug,
            category,
            title: data.frontMatter.title,
            originalDoc: data.originalDoc,
            success: true,
            fileContent: completeDocument,
            imageList,
            mermaidList,
            inlineImageList
        },
        binary: { data: Buffer.from(completeDocument, 'utf8') }
    };
    console.log(`--- [合并内容] 节点成功处理: ${fileName}, 图片:${imageList.length}, Mermaid:${mermaidList.length}, Drawing:${inlineImageList.length} ---`);
    return finalOutput;

} catch (error) {
    console.error("--- [合并内容] 节点发生错误 ---", error.message);
    console.error("错误堆栈:", error.stack);
    return [];
}

// 准备资源下载命令：处理普通图片（Google Drive）+ Mermaid 图表（mermaid.ink）
console.log("--- [准备资源下载命令] 节点开始执行 ---");
try {
    const input = $input.first();
    const data = input.json;

    const imageList = data.imageList || [];
    const mermaidList = data.mermaidList || [];
    const inlineImageList = data.inlineImageList || [];
    const slug = data.slug || '';
    const category = data.category || '';

    if (!slug || !category) {
        console.error('slug 或 category 为空，跳过资源下载');
        return { json: { ...data, imageDownloadScript: `echo "SKIP: slug or category empty"` } };
    }

    const basePath = `/Users/matthewyin/Coding/nssa/src/content/posts/${category}/${slug}`;
    const allCommands = [`mkdir -p '${basePath}'`];

    // 1. Google Drive 图片下载命令
    imageList.forEach(img => {
        const safeUrl = img.url.replace(/'/g, "'\\''" );
        allCommands.push(`curl -L -s --max-time 30 -o '${basePath}/${img.localFileName}' '${safeUrl}' && echo "IMG_OK: ${img.localFileName}" || echo "IMG_FAIL: ${img.localFileName}"`);
    });

    // 2. Mermaid 图表渲染命令（调用 mermaid.ink 免费 API）
    // API 格式：https://mermaid.ink/svg/{base64url_encoded_config}
    mermaidList.forEach(m => {
        const mermaidUrl = `https://mermaid.ink/svg/${m.base64Code}`;
        allCommands.push(`curl -L -s --max-time 60 -o '${basePath}/${m.localFileName}' '${mermaidUrl}' && echo "MERMAID_OK: ${m.localFileName}" || echo "MERMAID_FAIL: ${m.localFileName}"`);
    });

    // 3. Base64 内联图片（Google Drawing）写入命令
    inlineImageList.forEach(img => {
        allCommands.push(`python3 -c "import base64; open('${basePath}/${img.localFileName}','wb').write(base64.b64decode('${img.base64Data}'))" && echo "DRAWING_OK: ${img.localFileName}" || echo "DRAWING_FAIL: ${img.localFileName}"`);
    });

        allCommands.push(`echo "RESOURCE_DONE: img=${imageList.length} mermaid=${mermaidList.length} drawing=${inlineImageList.length} slug=${slug}"`);

    const script = allCommands.join('\n');
    console.log(`生成了 ${imageList.length} 条图片命令 + ${mermaidList.length} 条 Mermaid 命令 + ${inlineImageList.length} 条 Drawing 命令`);
    return { json: { ...data, imageDownloadScript: script } };

} catch (error) {
    console.error('准备资源下载命令失败:', error.message);
    return { json: { ...$input.first().json, imageDownloadScript: `echo "ERROR: ${error.message}"` } };
}

// 检查文件是否存在
const checkResult = $input.first();
const originalDoc = $('Loop Over Items').first().json;

// 获取SSH命令的输出
const output = checkResult.json.stdout.trim();

// 查找RESULT行
const lines = output.split('\n');
const resultLine = lines.find(line => line.startsWith('RESULT:'));
const result = resultLine ? resultLine.split(':')[1].trim() : 'NOT_EXISTS';

if (result === 'EXISTS') {
  // 文件已存在，跳过处理
  return {
    json: {
      ...originalDoc, 
      fileExists: true,
      skipProcessing: true,
      message: `文件已存在，跳过处理: ${originalDoc.name}` // ✅ 正确消息
    }
  };
}
else {
  // 文件不存在，需要处理
  return {
    json: {
      ...originalDoc,
      fileExists: false,
      skipProcessing: false,
      message: `文件不存在，开始处理: ${originalDoc.name}` // ✅ 正确消息
    }
  };
}

// 处理子文件夹数据，为每个文件夹创建查询
const response = $input.first().json;

if (!response.files || response.files.length === 0) {
  console.log('没有找到子文件夹');
  return [];
}

console.log(`找到 ${response.files.length} 个子文件夹`);

// 为每个文件夹创建独立的查询任务
return response.files.map(folder => ({
  json: {
    folderId: folder.id,
    folderName: folder.name,
    queryUrl: `https://www.googleapis.com/drive/v3/files?q='${folder.id}' in parents and mimeType='application/vnd.google-apps.document'&fields=files(id,name,mimeType,modifiedTime,parents,webViewLink)`
  }
}));

// 文件质量检测节点
const input = $input.first();
const data = input.json;

// 获取frontMatter数据
const frontMatter = data.frontMatter || {};
const title = frontMatter.title || '';
const description = frontMatter.description || '';
const tags = frontMatter.tags || [];

// 检测条件
const conditions = {
  emptyTitle: !title || title.trim() === '',
  inaccessibleDoc: title.includes('无法访问文档') || title.toLowerCase().includes('inaccessible'),
  emptyDescription: !description || description.trim() === '',
  emptyTags: !Array.isArray(tags) || tags.length === 0
};

// 判断是否需要删除
const shouldDelete = conditions.emptyTitle || conditions.inaccessibleDoc || conditions.emptyDescription || conditions.emptyTags;

// 构建检测结果
const result = {
  json: {
    ...data,
    qualityCheck: {
      passed: !shouldDelete,
      shouldDelete: shouldDelete,
      conditions: conditions,
      issues: []
    }
  }
};

// 记录具体问题
if (conditions.emptyTitle) result.json.qualityCheck.issues.push('标题为空');
if (conditions.inaccessibleDoc) result.json.qualityCheck.issues.push('文档无法访问');
if (conditions.emptyDescription) result.json.qualityCheck.issues.push('描述为空');
if (conditions.emptyTags) result.json.qualityCheck.issues.push('标签为空');

console.log(`质量检测 - 文件: ${data.fileName}`);
console.log(`标题: "${title}"`);
console.log(`描述长度: ${description.length}`);
console.log(`标签数量: ${tags.length}`);
console.log(`检测结果: ${shouldDelete ? '需要删除' : '质量合格'}`);
if (shouldDelete) {
  console.log(`问题列表: ${result.json.qualityCheck.issues.join(', ')}`);
}

return result;
